86	func (s *cleanupAdvanceAwareStore) ReadyExecution() ([]bead.Bead, error) {
87		ready := atomic.AddInt32(s.readyCalls, 1)
88		if ready == 1 {
89			atomic.StoreInt32(&s.firstReadyCleanupCount, atomic.LoadInt32(s.cleanupCalls))
90		}
91		if ready == 2 && atomic.LoadInt32(s.cleanupCalls) <= atomic.LoadInt32(&s.firstReadyCleanupCount) {
92			s.t.Fatalf("cleanup must run again before the next claim after setup failure")
93		}
94		return s.ExecuteBeadLoopStore.ReadyExecution()
95	}
