284	type blockingCleanupRunner struct {
285		started   chan struct{}
286		release   chan struct{}
287		calls     int32
288		active    int32
289		maxActive int32
290	}
291	
292	func (r *blockingCleanupRunner) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
293		atomic.AddInt32(&r.calls, 1)
294		active := atomic.AddInt32(&r.active, 1)
295		for {
296			prev := atomic.LoadInt32(&r.maxActive)
297			if active <= prev || atomic.CompareAndSwapInt32(&r.maxActive, prev, active) {
298				break
299			}
300		}
301		if r.started != nil {
302			select {
303			case <-r.started:
304			default:
305				close(r.started)
306			}
307		}
308		select {
309		case <-ctx.Done():
310		case <-r.release:
311		}
312		atomic.AddInt32(&r.active, -1)
313		return ExecutionCleanupSummary{}, nil
314	}
