354	func TestBackgroundCleanupEndToEnd_UsesLockAndJitter(t *testing.T) {
355		projectRoot := t.TempDir()
356		require.NoError(t, os.MkdirAll(filepath.Join(projectRoot, ".ddx"), 0o755))
357	
358		delay := jitteredCleanupDelay(10*time.Minute, rand.New(rand.NewSource(1)))
359		assert.GreaterOrEqual(t, delay, 8*time.Minute)
360		assert.LessOrEqual(t, delay, 12*time.Minute)
361	
362		runner := &blockingCleanupRunner{
363			started: make(chan struct{}),
364			release: make(chan struct{}),
365		}
366		runnerSummary := ExecutionCleanupSummary{
367			ProjectRoot:          projectRoot,
368			TempRoot:             filepath.Join(projectRoot, ".ddx", "tmp"),
369			RemovedRunStateFiles: 1,
370			BytesReclaimed:       1,
371			InodesReclaimed:      1,
372		}
373		originalCleanup := runner.Cleanup
374		wrappedRunner := cleanupRunnerFunc(func(ctx context.Context) (ExecutionCleanupSummary, error) {
375			_, err := originalCleanup(ctx)
376			return runnerSummary, err
377		})
378	
379		type cleanupEvent struct {
380			typ    string
381			reason string
382		}
383		var (
384			eventsMu sync.Mutex
385			events   []cleanupEvent
386		)
387		emit := func(typ string, data map[string]any) {
388			reason, _ := data["reason"].(string)
389			eventsMu.Lock()
390			events = append(events, cleanupEvent{typ: typ, reason: reason})
391			eventsMu.Unlock()
392		}
393		eventCount := func(typ string) int {
394			eventsMu.Lock()
395			defer eventsMu.Unlock()
396			count := 0
397			for _, ev := range events {
398				if ev.typ == typ {
399					count++
400				}
401			}
402			return count
403		}
404	
405		ctx, cancel := context.WithCancel(context.Background())
406		defer cancel()
407		tickA := make(chan time.Time, 4)
408		tickB := make(chan time.Time, 4)
409		stopA := startExecutionCleanupWorker(ctx, projectRoot, wrappedRunner, time.Hour, tickA, io.Discard, emit)
410		stopB := startExecutionCleanupWorker(ctx, projectRoot, wrappedRunner, time.Hour, tickB, io.Discard, emit)
411	
412		tickA <- time.Unix(100, 0)
413		select {
414		case <-runner.started:
415		case <-time.After(2 * time.Second):
416			t.Fatal("first cleanup pass did not start")
417		}
418		assert.Equal(t, int32(1), atomic.LoadInt32(&runner.calls))
419		assert.Equal(t, int32(1), atomic.LoadInt32(&runner.active))
420	
421		tickB <- time.Unix(101, 0)
422		require.Eventually(t, func() bool {
423			return eventCount("cleanup.skipped") >= 1
424		}, 2*time.Second, 10*time.Millisecond)
425		assert.Equal(t, int32(1), atomic.LoadInt32(&runner.calls), "second worker must skip while project cleanup lock is held")
426		assert.Equal(t, int32(1), atomic.LoadInt32(&runner.maxActive), "cleanup passes must not overlap")
427	
428		close(runner.release)
429		require.Eventually(t, func() bool {
430			return eventCount("cleanup.pass") >= 1
431		}, 2*time.Second, 10*time.Millisecond)
432		assert.Equal(t, int32(0), atomic.LoadInt32(&runner.active))
433	
434		tickA <- time.Unix(102, 0)
435		require.Eventually(t, func() bool {
436			return atomic.LoadInt32(&runner.calls) >= 2 && eventCount("cleanup.pass") >= 2
437		}, 2*time.Second, 10*time.Millisecond)
438	
439		cancel()
440		stopA()
441		stopB()
442	}
