20	// ExecutionsMirrorLogFile records mirror upload attempts and failures so
21	// operators can diagnose mirror-side issues without re-running execute-bead.
22	const ExecutionsMirrorLogFile = ".ddx/agent-logs/mirror.log"
23	
24	// MirrorIndexEntry is one row of the local mirror-index.jsonl pointer file.
25	type MirrorIndexEntry struct {
26		AttemptID  string    `json:"attempt_id"`
27		BeadID     string    `json:"bead_id,omitempty"`
28		MirrorURI  string    `json:"mirror_uri"`
29		UploadedAt time.Time `json:"uploaded_at"`
30		ByteSize   int64     `json:"byte_size"`
31		Kind       string    `json:"kind"`
32	}
