// ExecutionsMirrorConfig describes the out-of-band archive target for the
// local-tier evidence bundle: .ddx/executions/<attempt>/, the attempt's
// agent-log, and optionally .ddx/workers/<worker-id>/. A configured kind
// plus path is enough to enable mirroring; missing entries leave mirroring
// disabled (kind defaults to none).
//
// Per-attempt mirror layout (local-dir backend):
//
//	<rendered-path>/
//	  manifest.json, prompt.md, result.json, ...
//	  agent-logs/agent-<session-id>.jsonl  (when include_agent_logs is unset or true)
//	  workers/<worker-id>/...              (when include_workers is true)
type ExecutionsMirrorConfig struct {
	Kind    string   `yaml:"kind,omitempty" json:"kind,omitempty"`
	Path    string   `yaml:"path,omitempty" json:"path,omitempty"`
	Include []string `yaml:"include,omitempty" json:"include,omitempty"`
	Async   *bool    `yaml:"async,omitempty" json:"async,omitempty"`
	// RetentionDays is the mirror's own retention window independent of the
	// in-tree RetainDays. Zero means the operator manages mirror pruning
	// out-of-band; DDx does not auto-prune the mirror for v1.
	RetentionDays int `yaml:"retention_days,omitempty" json:"retention_days,omitempty"`
	// IncludeAgentLogs controls whether the attempt's agent-log file is copied
	// to the mirror. Nil (unset) and true both enable copying; false disables.
	IncludeAgentLogs *bool `yaml:"include_agent_logs,omitempty" json:"include_agent_logs,omitempty"`
	// IncludeWorkers controls whether the worker runtime directory
	// (.ddx/workers/<worker-id>/) is copied to the mirror. False by default
	// because worker dirs are large and rarely useful retrospectively.
	IncludeWorkers bool `yaml:"include_workers,omitempty" json:"include_workers,omitempty"`
}

