// MirrorBundle uploads one bundle synchronously via the configured backend
// and appends a row to the local mirror-index.jsonl pointer file. Returns
// the index entry on success.
//
// After the execution bundle is copied, the agent-log and worker directory
// are copied into sibling subdirectories within the rendered mirror path when
// their respective config flags are set. Copy failures for these supplementary
// paths are logged but do not fail the call — only the execution bundle copy
// is required for a successful return.
func MirrorBundle(req MirrorRequest) (*MirrorIndexEntry, error) {
	if req.Cfg == nil || strings.TrimSpace(req.Cfg.Kind) == "" || strings.TrimSpace(req.Cfg.Path) == "" {
		return nil, fmt.Errorf("mirror not configured")
	}
	backend, err := NewMirrorBackend(req.Cfg.Kind)
	if err != nil {
		return nil, err
	}
	if _, err := os.Stat(req.BundleDir); err != nil {
		return nil, fmt.Errorf("bundle dir %s: %w", req.BundleDir, err)
	}

	dest := RenderMirrorPath(req.Cfg.Path, projectName(req.ProjectRoot), req.AttemptID, req.BeadID)
	filter := IncludeFilter(req.Cfg.Include)

	mirrorURI, bytes, err := backend.Upload(dest, req.BundleDir, filter)
	if err != nil {
		return nil, fmt.Errorf("mirror upload: %w", err)
	}

	entry := &MirrorIndexEntry{
		AttemptID:  req.AttemptID,
		BeadID:     req.BeadID,
		MirrorURI:  mirrorURI,
		UploadedAt: time.Now().UTC(),
		ByteSize:   bytes,
		Kind:       backend.Kind(),
	}
	if err := AppendMirrorIndex(req.ProjectRoot, entry); err != nil {
		return entry, fmt.Errorf("appending mirror-index.jsonl: %w", err)
	}

	// Copy agent-log for this attempt (best-effort; failures are logged).
	if req.SessionID != "" && mirrorAgentLogsEnabled(req.Cfg) {
		agentLogName := "agent-" + req.SessionID + ".jsonl"
		agentLogSrc := filepath.Join(req.ProjectRoot, ".ddx", "agent-logs", agentLogName)
		agentLogDestDir := filepath.Join(dest, "agent-logs")
		if cpErr := mirrorSingleFile(agentLogSrc, filepath.Join(agentLogDestDir, agentLogName)); cpErr != nil {
			LogMirrorCopyFailed(req.ProjectRoot, req.AttemptID, req.BeadID, "agent-log", cpErr)
		}
	}

	// Copy worker directory for this attempt (best-effort; failures are logged).
	if req.WorkerID != "" && req.Cfg.IncludeWorkers {
		workerSrc := filepath.Join(req.ProjectRoot, ".ddx", "workers", req.WorkerID)
		workerDest := filepath.Join(dest, "workers", req.WorkerID)
		if cpErr := mirrorDir(workerSrc, workerDest); cpErr != nil {
			LogMirrorCopyFailed(req.ProjectRoot, req.AttemptID, req.BeadID, "worker-dir", cpErr)
		}
	}

	return entry, nil
}

// mirrorSingleFile copies one file from src to dst, creating parent dirs as needed.
// Returns an error when src does not exist.
func mirrorSingleFile(src, dst string) error {
	if err := os.MkdirAll(filepath.Dir(dst), 0o755); err != nil {
		return fmt.Errorf("creating mirror dir: %w", err)
	}
	_, err := copyFile(src, dst)
	return err
}

// mirrorDir copies the directory tree at src into dst. Missing src is silently
// skipped (workers dir may not exist for every attempt).
func mirrorDir(src, dst string) error {
	if _, err := os.Stat(src); err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	if err := os.MkdirAll(dst, 0o755); err != nil {
		return fmt.Errorf("creating mirror dir %s: %w", dst, err)
	}
	return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			return nil
		}
		rel, relErr := filepath.Rel(src, path)
		if relErr != nil {
			return relErr
		}
		destFile := filepath.Join(dst, rel)
		if mkErr := os.MkdirAll(filepath.Dir(destFile), 0o755); mkErr != nil {
			return mkErr
		}
		_, cpErr := copyFile(path, destFile)
		return cpErr
	})
}

