}

// LogMirrorCopyFailed records a mirror-copy-failed event to mirror.log.
// kind identifies which supplementary part failed (e.g. "agent-log", "worker-dir").
// Copy failures do not block attempt finalization.
func LogMirrorCopyFailed(projectRoot, attemptID, beadID, kind string, err error) {
	line := fmt.Sprintf("%s mirror-copy-failed attempt=%s bead=%s kind=%s err=%q\n",
		time.Now().UTC().Format(time.RFC3339), attemptID, beadID, kind, err.Error())
	appendMirrorLog(projectRoot, line)
}

// TestMirror_CopiesExecutionDir verifies the local-dir backend copies all
// execution bundle files to the mirror destination.
func TestMirror_CopiesExecutionDir(t *testing.T) {
	projectRoot := t.TempDir()
	const attemptID = "20260511T000000-aabbccdd"
	const beadID = "ddx-mirror-execdir"

	bundleDir := filepath.Join(projectRoot, ".ddx", "executions", attemptID)
	require.NoError(t, os.MkdirAll(bundleDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(bundleDir, "manifest.json"), []byte(`{"attempt_id":"`+attemptID+`"}`), 0o644))
	require.NoError(t, os.WriteFile(filepath.Join(bundleDir, "result.json"), []byte(`{"status":"success"}`), 0o644))

	mirrorRoot := t.TempDir()
	cfg := &config.ExecutionsMirrorConfig{
		Kind: "local",
		Path: filepath.Join(mirrorRoot, "{attempt_id}"),
	}
	entry, err := MirrorBundle(MirrorRequest{
		ProjectRoot: projectRoot,
		AttemptID:   attemptID,
		BeadID:      beadID,
		BundleDir:   bundleDir,
		Cfg:         cfg,
	})
	require.NoError(t, err)
	require.NotNil(t, entry)

	assert.FileExists(t, filepath.Join(mirrorRoot, attemptID, "manifest.json"))
	assert.FileExists(t, filepath.Join(mirrorRoot, attemptID, "result.json"))
}

