// TestMirror_CopyFailure_DoesNotBlockFinalization verifies that a failure to
// copy the agent-log (e.g. missing file) is logged but does not return an error
// from MirrorBundle — the execution bundle is mirrored and the entry returned.
func TestMirror_CopyFailure_DoesNotBlockFinalization(t *testing.T) {
	projectRoot := t.TempDir()
	const attemptID = "20260511T000004-aabbccdd"
	const beadID = "ddx-mirror-copyfail"
	const sessionID = "sess-mirror-missing"

	bundleDir := filepath.Join(projectRoot, ".ddx", "executions", attemptID)
	require.NoError(t, os.MkdirAll(bundleDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(bundleDir, "result.json"), []byte(`{}`), 0o644))

	// Do NOT create the agent-log — simulates a missing/unwritten log file.

	mirrorRoot := t.TempDir()
	cfg := &config.ExecutionsMirrorConfig{
		Kind: "local",
		Path: filepath.Join(mirrorRoot, "{attempt_id}"),
		// IncludeAgentLogs unset → defaults to true; file is missing → copy fails
	}
	entry, err := MirrorBundle(MirrorRequest{
		ProjectRoot: projectRoot,
		AttemptID:   attemptID,
		BeadID:      beadID,
		BundleDir:   bundleDir,
		SessionID:   sessionID,
		Cfg:         cfg,
	})
	// Must NOT return an error — mirror failure is best-effort.
	require.NoError(t, err, "copy failure must not block finalization")
	require.NotNil(t, entry)
	assert.Equal(t, attemptID, entry.AttemptID)

	// Execution bundle was still mirrored.
	assert.FileExists(t, filepath.Join(mirrorRoot, attemptID, "result.json"))

	// mirror.log must record the failure.
	logPath := filepath.Join(projectRoot, ExecutionsMirrorLogFile)
	logData, readErr := os.ReadFile(logPath)
	require.NoError(t, readErr)
	assert.Contains(t, string(logData), "mirror-copy-failed")
	assert.Contains(t, string(logData), "agent-log")
}

